function solve(n: number): string {
    const nSquared = n * n;
    const hexPart = nSquared.toString(16).toUpperCase();

    const nCubed = n * n * n;
    const base36Digits = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    let temp = nCubed;
    let base36Chars = [];

    if (temp === 0) {
        base36Chars.push('0');
    } else {
        while (temp > 0) {
            const remainder = temp % 36;
            base36Chars.push(base36Digits[remainder]);
            temp = Math.floor(temp / 36);
        }
    }

    const base36Part = base36Chars.reverse().join('');
    return hexPart + base36Part;
}
